effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

vec3 rgb2hsv(vec3 c)
{
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);

    float luminance = dot(texColor.rgb, luminanceWeighting);

    vec2 s = step(vec2(0.,0.), acLayerNorm) - step(vec2(1.,1.), acLayerNorm);
    float maskFactor = s.x * s.y;

    vec4 outColor = vec4(0.0);

    if( texColor.a > 0.0 )
        texColor.rgb /= texColor.a;

    texColor.rgb = rgb2hsv(texColor.rgb);

    if( hue==0 ) {
        outColor.r = texColor.r;
    } else if( hue==1 ) {
        outColor.r = texColor.g;
    } else if( hue==2 ) {
        outColor.r = texColor.b;
    } else if( hue==3 ) {
        outColor.r = texColor.a;
    } else if( hue==4 ) {
        outColor.r = luminance;
    } else if( hue==5 ) {
        outColor.r = 0.0;
    } else {
        outColor.r = 1.0;
    }

    if( sat==0 ) {
        outColor.g = texColor.r;
    } else if( sat==1 ) {
        outColor.g = texColor.g;
    } else if( sat==2 ) {
        outColor.g = texColor.b;
    } else if( sat==3 ) {
        outColor.g = texColor.a;
    } else if( sat==4 ) {
        outColor.g = luminance;
    } else if( sat==5 ) {
        outColor.g = 0.0;
    } else {
        outColor.g = 1.0;
    }

    if( val==0 ) {
        outColor.b = texColor.r;
    } else if( val==1 ) {
        outColor.b = texColor.g;
    } else if( val==2 ) {
        outColor.b = texColor.b;
    } else if( val==3 ) {
        outColor.b = texColor.a;
    } else if( val==4 ) {
        outColor.b = luminance;
    } else if( val==5 ) {
        outColor.b = 0.0;
    } else {
        outColor.b = 1.0;
    }

    if( alpha==0 ) {
        outColor.a = texColor.r;
    } else if( alpha==1 ) {
        outColor.a = texColor.g;
    } else if( alpha==2 ) {
        outColor.a = texColor.b;
    } else if( alpha==3 ) {
        outColor.a = texColor.a;
    } else if( alpha==4 ) {
        outColor.a = luminance;
    } else if( alpha==5 ) {
        outColor.a = 0.0;
    } else {
        outColor.a = 1.0;
    }

    outColor.rgb = hsv2rgb(outColor.rgb);

    outColor.rgb *= outColor.a;

    gl_FragColor = outColor * maskFactor;
}
